INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-64311456-moex-00125', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於訴願法制，下列敘述何者錯誤？', '["訴願決定確定後，有拘束各關係機關之效力", "行政執行因義務人對原行政處分不服提起訴願而停止", "原行政處分經撤銷，原行政處分機關須重為處分者，應依訴願決定意旨 為之", "經聽證程序作成之行政處分，其救濟程序免除訴願及其先行程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00126', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '人民因行政機關怠為處分而提起訴願，受理訴願機關應如何決定？', '["訴願有理由時，應自行核定處分", "命應作為之機關為確認之處分", "訴願有理由時，撤銷另為適法之處分", "應作為之機關已為行政處分者，應認訴願為無理由，以決定駁回之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00127', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '有關行政訴訟程序之停止，下列敘述何者正確？', '["行政法院對受理事件所適用之法律，確信有牴觸憲法之疑義時，應停止 訴訟程序，聲請憲法法庭判決", "當事人不得以合意停止訴訟程序，但於公益之維護有礙者，不在此限", "行政法院就其受理訴訟之權限，與普通法院確定裁判之見解有異時，應 以裁定停止訴訟程序，並聲請憲法法庭判決", "訴訟程序當然或裁定停止期間，行政法院及當事人仍得為關於本案之訴 訟行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00128', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政法院與普通法院就審判權所生爭議之處理，下列敘述何者錯誤？', '["行政法院認其有審判權而為裁判經確定者，其他法院不受該裁判之羈束", "移送訴訟前如有急迫情形，行政法院應依當事人聲請或依職權為必要之 處分", "行政法院認其對訴訟無審判權者，應依職權以裁定將訴訟移送至有審判 權之管轄法院", "當事人對行政法院有無審判權有爭執者，行政法院應就此先為裁定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00129', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲收受某國稅局核定稅額通知書，通知書上載有應補徵稅額，若甲不服， 依法提起復查及訴願皆遭駁回，如仍不服，應提起何種訴訟以資救濟？', '["撤銷訴訟", "課予義務訴訟", "確認處分違法之訴", "確認處分無效之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00130', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列公法上爭議事件，何者屬於行政法院管轄？', '["社會秩序維護法之裁罰事件", "律師懲戒委員會之懲戒決定", "公職人員選舉當選無效之訴訟", "公務人員考績丙等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00131', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政訴訟調解規定之敘述，下列何者錯誤？', '["必要時，經行政法院許可者，得就訴訟標的以外之事項，併予調解", "當事人必須就訴訟標的有處分權，始得移付調解", "行政法院得將事件移付調解，毋須經當事人合意", "調解必須無礙公益之維護，始得移付調解"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00132', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依國家賠償法規定，關於因公共設施所致之國家賠償責任，下列敘述何者 正確？', '["開放水域之自然公物，無國家賠償法之適用", "公共設施，僅限於國家享有所有權之設施", "必須是公共設施在設置或管理上有所欠缺", "因公共設施所侵害之法益，僅限於生命或身體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00133', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於國家賠償，下列敘述何者錯誤？', '["公務員於退休前，因執行職務行使公權力，違法侵害甲之權利，該公務 員雖已退休，甲仍可主張國家賠償", "行政機關編制外之人員，於執行公文送達職務時，駕車撞傷乙，乙可主 張國家賠償", "交通部中央氣象署發布氣象預報違失，致民眾丙財產受有損害，丙可主 張國家賠償", "警員丁駕駛巡邏警車值勤，行經政府疏於修護之道路，致警車翻覆而受 傷，丁不得主張國家賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00134', 'disabled-64311456', 'disabled-64311456-moex-114-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '行政機關基於公益目的，依土地徵收條例之規定，徵收私人土地以興建國 民小學，原土地所有權人應獲得徵收補償，下列何者為補償的標準？', '["酌量補償", "合理補償", "衡平補償", "回復補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:40+00:00", "source_pdf_sha1": "9fd329be3c64", "answer_pdf_sha1": "2f12e5218632", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "404", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
